#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha, double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Parallelise the outermost loop (rows of C).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // Obtain raw pointers for the current row of A, B, and C.
        double* Ap = A[i].data();          // NK elements
        double* Cp = C[i].data();          // NJ elements
        // Scale C[i][j] by beta first.
        for (int j = 0; j < nj; ++j) {
            Cp[j] *= beta;
        }

        // Compute the dot products for this row.
        for (int k = 0; k < nk; ++k) {
            double a_ik = alpha * Ap[k];
            double* Bp = B[k].data();     // NJ elements
            for (int j = 0; j < nj; ++j) {
                Cp[j] += a_ik * Bp[j];
            }
        }
    }
}
