/*
 * Optimised trmm kernel.
 * The algorithm is identical to the reference implementation:
 *   B := alpha * A^T * B,
 * where A is M×M and B is M×N.
 */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // Flatten the 2‑D vectors to 1‑D pointers for faster access.
    double *a = &A[0][0];
    double *b = &B[0][0];

    /* Parallelise the outer two loops with OpenMP. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = b[i * n + j];          // current B[i][j]
            for (int k = i + 1; k < m; ++k) {
                sum += a[k * m + i] * b[k * n + j];
            }
            b[i * n + j] = alpha * sum;          // store back
        }
    }
}
