        double qi = 0.0;
        double* Ai = A[i].data();
        for (int j = 0; j < m; ++j) {
            double aij = Ai[j];
            s[j] += ri * aij;          // s[j] += r[i] * A[i][j];
            qi += aij + p[j];          // q[i] += A[i][j] + p[j];
        }
        q[i] = qi;
