#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    // Flatten the 2D std::vector for faster data access
    // C is symmetric (NxN), but we only touch the lower triangle (j ≤ i)
    // Note: C and A are stored in row-major order

    // Create strides for easier indexing
    const std::ptrdiff_t strideC = n;
    const std::ptrdiff_t strideA = m;

    // Pointers to the underlying data
    double* c_data = &C[0][0];
    const double* a_data = &A[0][0];

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Scale the lower triangle of C by beta
        double* ci = c_data + i * strideC;    // row i start
        for (int j = 0; j <= i; ++j) {
            ci[j] *= beta;
        }

        // Accumulate outer products of row i of A with all rows j of A
        const double* ai = a_data + i * strideA; // row i of A
        for (int k = 0; k < m; ++k) {
            double aik = ai[k];
            const double* aj = a_data + k; // column k as row vector (j varies)
            for (int j = 0; j <= i; ++j) {
                ci[j] += alpha * aik * aj[j * strideA];
            }
        }
    }
}
