#include <vector>
#include <omp.h>

constexpr double INV3 = 0.33333;

void kernel_jacobi_1d(int tsteps, int n, std::vector<double>& A,
                      std::vector<double>& B) {
    // Ensure the threads look at the same stride for better data locality
    const int chunk = 64; // cache line sized chunk
    double *pa = A.data();
    double *pb = B.data();

    for (int t = 0; t < tsteps; ++t) {
        /* First half‑step update of B from A */
        #pragma omp parallel for schedule(static, chunk) \
                                    nowait
        for (int i = 1; i < n - 1; ++i) {
            pb[i] = INV3 * (pa[i-1] + pa[i] + pa[i+1]);
        }

        /* Second half‑step update of A from B */
        #pragma omp parallel for schedule(static, chunk) \
                                    nowait
        for (int i = 1; i < n - 1; ++i) {
            pa[i] = INV3 * (pb[i-1] + pb[i] + pb[i+1]);
        }
    }
}
```
The code keeps the same semantics as the original while

* using raw pointers for minimal indirection,
* parallelising each loop with OpenMP,
* biasing the schedule to `static` with a cache‑line sized chunk for better
  data locality,
* avoiding redundant boundary checks.

No changes to the function signature or observable behaviour.

