// Optimized Floyd‑Warshall suitable for GCC -std=c++17, -O2, -fopenmp
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

// Helper to obtain raw access to the 2‑D vector
inline int* row_ptr(std::vector<std::vector<int>>& mat, std::size_t r) noexcept {
    return mat[r].data();
}

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Parallelise over the outer i‑loop for each fixed k.
    // Use a standard for‑loop to avoid bounds‑check overhead.
    for (int k = 0; k < n; ++k) {
        int* row_k = row_ptr(path, k);               // path[k][*]
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int* row_i = row_ptr(path, i);           // path[i][*]
            int val_ik = row_i[k];                   // path[i][k]
            for (int j = 0; j < n; ++j) {
                int d = val_ik + row_k[j];           // path[i][k] + path[k][j]
                int& dst = row_i[j];
                if (d < dst) dst = d;                // fast min: dst = std::min(dst, d)
            }
        }
    }
}
