#include <vector>
#include <cmath>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    /* Parallelize the outer loop (each i‑th row is independent after the
       preceding rows have been finished). The compiler at -O2 with
       -fopenmp will do a good job of vectorizing the inner loops.  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* const Ai = A[i].data();         // row i

        /* --- Compute the off‑diagonal elements A[i][j] (j < i) --- */
        for (int j = 0; j < i; ++j) {
            double* const Aj = A[j].data();     // row j
            double sum = 0.0;
            /* Accumulate the dot product A[i][k] * A[j][k] for k < j */
            for (int k = 0; k < j; ++k) {
                sum += Ai[k] * Aj[k];
            }
            Ai[j] = (Ai[j] - sum) / Aj[j];
        }

        /* --- Compute the diagonal element A[i][i] --- */
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += Ai[k] * Ai[k];
        }
        Ai[i] = std::sqrt(Ai[i] - sum);
    }
}
