```cpp
#include <vector>
#include <cstring>
#include <omp.h>

/*
 * Optimised triangular solve.
 * Behaviour is identical to the reference implementation but uses
 * raw pointer arithmetic and a local variable cache to reduce
 * vector overhead.  The function is intentionally single-threaded
 * because the forward substitution has data dependence.
 */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Local cache for the current i-th row pointer
    const double *row;
    // Temporary variables for reduction
    double accum;

    for (int i = 0; i < n; ++i)
    {
        row  = L[i].data();          // pointer to i‑th row
        accum = b[i];                // start with RHS entry

        // Unroll the inner loop in blocks of 4
        int j = 0;
        for (; j <= i - 4; j += 4)
        {
            accum -= row[j]   * x[j];
            accum -= row[j+1] * x[j+1];
            accum -= row[j+2] * x[j+2];
            accum -= row[j+3] * x[j+3];
        }
        // Remaining elements
        for (; j < i; ++j)
        {
            accum -= row[j] * x[j];
        }

        x[i] = accum / row[i];
    }
}
