```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A)
{
    // Convert the 2‑D std::vector to a raw continuous array for faster access
    std::vector<double> a_row_major(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            a_row_major[i * n + j] = A[i][j];

    const double* const a = a_row_major.data();
    const double* const y1 = y_1.data();
    const double* const y2 = y_2.data();
    double* const x1_ptr = x1.data();
    double* const x2_ptr = x2.data();

    // First accumulation: x1[i] += sum_j A[i][j] * y1[j]
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double* const a_row = a + i * n;
        double tmp = x1_ptr[i];
        for (int j = 0; j < n; ++j)
            tmp += a_row[j] * y1[j];
        x1_ptr[i] = tmp;
    }

    // Second accumulation: x2[i] += sum_j A[j][i] * y2[j]
    // To preserve the element‑wise dependence on column i, we iterate
    // over i and accumulate along j.  The transposed access is kept
    // contiguous by re‑indexing into the row‑major array.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp = x2_ptr[i];
        for (int j = 0; j < n; ++j)
            tmp += a[j * n + i] * y2[j];
        x2_ptr[i] = tmp;
    }
}
