```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    // Flatten the 2D matrices into 1‑D arrays for cache‑line friendliness
    const size_t N = static_cast<size_t>(n);
    const size_t M = static_cast<size_t>(m);
    std::vector<double> C_flat(N * N);
    std::vector<double> A_flat(N * M);
    std::vector<double> B_flat(N * M);

    // Copy data into flattened arrays
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) C_flat[i * N + j] = C[i][j];
        for (size_t j = 0; j < M; ++j) A_flat[i * M + j] = A[i][j];
        for (size_t j = 0; j < M; ++j) B_flat[i * M + j] = B[i][j];
    }

    // Main computation
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // beta‑scale lower triangle
        for (int j = 0; j <= i; ++j) {
            C_flat[i * N + j] *= beta;
        }

        // incremental update
        for (int k = 0; k < m; ++k) {
            double alphaBik = alpha * B_flat[i * M + k];
            double alphaAik = alpha * A_flat[i * M + k];
            for (int j = 0; j <= i; ++j) {
                C_flat[i * N + j] +=
                    A_flat[j * M + k] * alphaBik + B_flat[j * M + k] * alphaAik;
            }
        }
    }

    // Copy the results back into the original C matrix
    for (size_t i = 0; i < N; ++i)
        for (size_t j = 0; j < N; ++j)
            C[i][j] = C_flat[i * N + j];
}
