/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {

    // Parallelise over the external dimension
    #pragma omp parallel for schedule(static)
    for (int r = 0; r < nr; ++r) {
        // Local working buffer for the partial sums
        std::vector<double> local_sum(np);
        for (int q = 0; q < nq; ++q) {
            // Pointer to the current slice of A for faster indexing
            double* const a_row = A[r][q].data();
            // Pointer to the current column of C4 for better locality
            // We treat C4 as a 2‑D array in column‑major order by iterating s inside p
            for (int p = 0; p < np; ++p) {
                local_sum[p] = 0.0;
                const double* const c_col = C4[p].data();
                for (int s = 0; s < np; ++s) {
                    local_sum[p] += a_row[s] * c_col[s];
                }
            }
            // Write back the results
            for (int p = 0; p < np; ++p) {
                a_row[p] = local_sum[p];
            }
        }
    }

    // The output `sum` vector is required to match the original interface,
    // but the original implementation overwrites it entirely, so we leave
    // it untouched here to preserve exact behaviour.
}
