/* Reference layout
 *   A : n×n (row major)
 *   u1,u2,v1,v2,w,x,y,z : n
 *
 * All arguments are passed by reference to guarantee exact behaviour.
 */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {
    const int N = n;
    const double * restrict pA = (double*)nullptr;   // placeholder not used
    // ---------- 1. A ← A + u1 * v1ᵀ + u2 * v2ᵀ ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        double * restrict Ai = A[i].data();   // row pointer
        for (int j = 0; j < N; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // ---------- 2. x ← x + beta * Aᵀ * y ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        double xi = x[i];
        for (int j = 0; j < N; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi;
    }

    // ---------- 3. x ← x + z ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        x[i] += z[i];
    }

    // ---------- 4. w ← w + alpha * A * x ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        double wi = w[i];
        double * restrict Ai = A[i].data();
        for (int j = 0; j < N; ++j) {
            wi += alpha * Ai[j] * x[j];
        }
        w[i] = wi;
    }
}
