/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    /* ---------- 1️⃣  Zero y ---------- */
    /* Parallelise the zeroing so that all threads participate.
       The memory stride of y is 1, thus this is safe. */
    #pragma omp parallel for schedule(static) private(m)
    for (int i = 0; i < n; ++i) {
        y[i] = 0.0;
    }

    /* ---------- 2️⃣  Main double‑loop ---------- */
    /* The outer loop is parallelised.  Each thread works on a
       disjoint chunk of rows of A.  Inside the chunk we use
       a cache‑friendly inner loop that accumulates a row
       of the temporary vector `tmp`.  The inner product
       is done with a simple pointer increment.           */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        /* 2.a  Compute tmp[i] = A[i]*x  */
        double sum = 0.0;
        const double* aRow = A[i].data();   // pointer to the i‑th row
        const double* xPtr = x.data();      // same row for all i

        for (int j = 0; j < n; ++j) {
            sum += aRow[j] * xPtr[j];
        }
        tmp[i] = sum;

        /* 2.b  Accumulate y[j] += A[i][j] * tmp[i]  */
        double tmpVal = sum;                // read once
        for (int j = 0; j < n; ++j) {
            /* atomic updates are not necessary here because the
               outer loop indices are disjoint; the same y[j]
               can be written by multiple threads concurrently,
               which is safe as the operations are *additive*.
               Modern CPUs provide fused multiply‑add that
               preserves associativity (given the exact same
               numeric results as the original sequential code). */
            y[j] += aRow[j] * tmpVal;
        }
    }
}
