#include <cmath>
#include <vector>
#include <algorithm>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps          = 0.1;
    const double inv_sqrt_n   = 1.0 / std::sqrt(static_cast<double>(n));

    /* --- 1. Compute column means ------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* --- 2. Compute column std–devs --------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            sum += d * d;
        }
        double sd = std::sqrt(sum / n);
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    /* --- 3. Center & scale the matrix (in place) ------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = data[i][j] - mean[j];
            data[i][j] = v * inv_sqrt_n / stddev[j];
        }
    }

    /* --- 4. Compute upper‑triangular correlation matrix ------------- */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double val = 0.0;
            for (int k = 0; k < n; ++k)
                val += data[k][i] * data[k][j];
            corr[i][j] = corr[j][i] = val;
        }
    }
    corr[m-1][m-1] = 1.0;
}
