   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    const double w = 0.2;
    const size_t stride = static_cast<size_t>(n);

    /* Work with raw pointers for max cache friendliness */
    double *ptrA = flat_ptr(A);
    double *ptrB = flat_ptr(B);

    /* Parallelise over the outermost loop with dynamic scheduling.
       Using a modest chunk size keeps the load balanced while
       reducing scheduling overhead. */
#pragma omp parallel for schedule(dynamic, 64) collapse(1)
    for (int t = 0; t < tsteps; ++t) {
        /* Phase 1: update B from A */
        for (int i = 1; i < n - 1; ++i) {
            size_t base = static_cast<size_t>(i) * stride;
            size_t im1 = static_cast<size_t>(i - 1) * stride;
            size_t ip1 = static_cast<size_t>(i + 1) * stride;
            for (int j = 1; j < n - 1; ++j) {
                size_t idx = base + j;
                ptrB[idx] = w * (ptrA[idx] +
                                 ptrA[idx - 1] +    // left
                                 ptrA[idx + 1] +    // right
                                 ptrA[ip1 + j] +    // down
                                 ptrA[im1 + j]);    // up
            }
        }

        /* Phase 2: update A from B */
        for (int i = 1; i < n - 1; ++i) {
            size_t base = static_cast<size_t>(i) * stride;
            size_t im1 = static_cast<size_t>(i - 1) * stride;
            size_t ip1 = static_cast<size_t>(i + 1) * stride;
