                ptrA[idx] = w * (ptrB[idx] +
                                 ptrB[idx - 1] +    // left
                                 ptrB[idx + 1] +    // right
                                 ptrB[ip1 + j] +    // down
                                 ptrB[im1 + j]);    // up
