/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /* Ensure that the 2‑D vectors use a row–major contiguous storage
       layout of the inner vectors.  The harness guarantees that.  */
    double* A_ptr = &A[0][0];
    double* R_ptr = &R[0][0];
    double* Q_ptr = &Q[0][0];

    const std::size_t stride = static_cast<std::size_t>(m);

#pragma omp parallel
    {
        for (int k = 0; k < n; ++k) {
            /* Compute the norm of the k‑th column of A */
            double nrm = 0.0;
#pragma omp simd reduction(+:nrm)
            for (int i = 0; i < m; ++i)
                nrm += A_ptr[i + k * stride] * A_ptr[i + k * stride];

            double Rkk = std::sqrt(nrm);
            R_ptr[k + k * stride] = Rkk;

            /* Normalize the k‑th column into Q */
#pragma omp simd
            for (int i = 0; i < m; ++i)
                Q_ptr[i + k * stride] = A_ptr[i + k * stride] / Rkk;

            /* Project remaining columns onto Q's k‑th column */
            for (int j = k + 1; j < n; ++j) {
                double rkj = 0.0;
#pragma omp simd reduction(+:rkj)
                for (int i = 0; i < m; ++i)
                    rkj += Q_ptr[i + k * stride] * A_ptr[i + j * stride];

                R_ptr[k + j * stride] = rkj;

                /* Subtract the projection from the remaining columns */
#pragma omp simd
                for (int i = 0; i < m; ++i)
                    A_ptr[i + j * stride] -= Q_ptr[i + k * stride] * rkj;
            }
        }
    }
}
