/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A)
{
    const double inv9 = 1.0 / 9.0;          // pre‑compute constant
    const int lastIdx = n - 2;              // last internal index

    /* The outer time loop must remain serial because each step
       depends on the previous one.  The inner 2‑D loop for a single
       time step can be parallelised safely because rank of
       parallelisation is over the independent rows. */
    for (int t = 0; t < tsteps; ++t) {
#pragma omp parallel for schedule(static) proc_bind(close)
        for (int i = 1; i <= lastIdx; ++i) {
            // Pointers to the three consecutive rows
            double* prev = &A[i-1][0];
            double* cur  = &A[i][0];
            double* next = &A[i+1][0];
            // iterate over columns with a small unroll
            int j = 1;
            for (; j <= lastIdx-3; j += 4) {
                // 4 independent updates per iteration
                for (int k = 0; k < 4; ++k) {
                    int c = j + k;
                    cur[c] = (prev[c-1] + prev[c] + prev[c+1] +
                              cur[c-1]  + cur[c]  + cur[c+1] +
                              next[c-1] + next[c] + next[c+1]) * inv9;
                }
            }
            // tail loop for remaining columns
            for (; j <= lastIdx; ++j) {
                cur[j] = (prev[j-1] + prev[j] + prev[j+1] +
                          cur[j-1]  + cur[j]  + cur[j+1] +
                          next[j-1] + next[j] + next[j+1]) * inv9;
            }
        }
    }
}
