 * 2‑Matrix Multiply (2mm) kernel – highly‑optimised version
 * 
 * The original function works on std::vector<std::vector<double>>.  This
 * version keeps the same public signature but works directly with the raw
 * row pointers for zero‑cache‑miss access.  The loops are parallelised
 * with OpenMP and the inner products are written in a way that allows
 * the compiler to auto‑vectorise.
 *********************************************************************/

#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D) 
{
    /* --------------------------------------------------------------------
       Step 1 – compute tmp = alpha * A * B
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const tmp_row = tmp[i].data();
        const double* const A_row = A[i].data();
        /* local copy of B rows pointers to avoid repeated lookup */
        double const * const * B_rows = reinterpret_cast<double const * const *>(B.data());
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += alpha * A_row[k] * B_rows[k][j];
            }
            tmp_row[j] = sum;
        }
    }

    /* --------------------------------------------------------------------
       Step 2 – compute D = beta * D + tmp * C
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const D_row = D[i].data();
        const double* const tmp_row = tmp[i].data();
        double const * const * C_rows = reinterpret_cast<double const * const *>(C.data());
        for (int j = 0; j < nl; ++j) {
            double sum = beta * D_row[j];
            for (int k = 0; k < nj; ++k) {
                sum += tmp_row[k] * C_rows[k][j];
            }
            D_row[j] = sum;
        }
    }
}
