/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    /* The algorithm is a classic LU decomposition without pivoting.
       The outermost loop over rows must be sequential because later
       rows depend on all former work.  Inside each row we have two
       distinct phases:
         1) compute the strictly lower part (j < i).  This is
            still sequential because A[i][k] for k < j must already
            be ready.
         2) compute the upper part (j >= i).  This phase depends only
            on already computed rows (all k < i) and on the current
            row's elements for k < i – thus each column j can be
            processed independently.  This is the only part we can
            parallelise safely.

       The code below keeps the exact numerical behaviour of the
       reference implementation, but adds a straightforward OpenMP
       pragma to parallelise the second nested loop.
    */

    for (int i = 0; i < n; ++i) {
        /* 1) Lower part: j < i */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            for (int k = 0; k < j; ++k)
                sum += A[i][k] * A[k][j];
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        /* 2) Upper part: j >= i  - this loop is parallelised */
#pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            for (int k = 0; k < i; ++k)
                sum += A[i][k] * A[k][j];
            A[i][j] -= sum;
        }
    }
}
