/* Parallelized and cache‑friendly Nussinov kernel.
   The public interface (vector of vectors) is preserved so
   the harness sees no change.  Internally the matrix is
   flattened into a contiguous 1‑D array to improve spatial
   locality and to reduce the overhead of std::vector‑of‑vectors.
*/

static inline int match(int b1, int b2) noexcept {
    return (b1 + b2 == 3) ? 1 : 0;
}

/* Utility to map a logical (i,j) index into a linear index.
   j runs from i+1..n-1, so we use a dense upper‑triangular layout:
      idx(i, j) = i * n + j   (full matrix is used for simplicity)
*/
inline size_t idx(size_t i, size_t j, size_t n) noexcept {
    return i * n + j;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    /* Flatten the 2‑D std::vector<int> into a contiguous 1‑D array */
    std::vector<int> buf(n * n);
    for (size_t i = 0; i < (size_t)n; ++i)
        std::copy(table[i].begin(), table[i].end(), buf.begin() + i * n);

    /* Main DP loop – processed diagonally (by increasing distance).
       We parallelise over the outer i‑loop via OpenMP. */
    #pragma omp parallel for schedule(static)
    for (int i = n - 2; i >= 0; --i) {            // start at n-2 (i+1 < n)
        for (int j = i + 1; j < n; ++j) {
            int best = buf[idx(i, j, n)];        // current value

            /* option 1: skip j */
            if (j - 1 >= 0)
                best = std::max(best, buf[idx(i, j - 1, n)]);

            /* option 2: skip i */
            if (i + 1 < n)
                best = std::max(best, buf[idx(i + 1, j, n)]);

            /* option 3: pair (i,j) */
            if (i + 1 < n && j - 1 >= 0) {
                best = std::max(best, buf[idx(i + 1, j - 1, n)] + match(seq[i], seq[j]));
            }

            /* option 4: split at k */
            for (int k = i + 1; k < j; ++k) {
                int val = buf[idx(i, k, n)] + buf[idx(k + 1, j, n)];
                if (val > best) best = val;
            }

            buf[idx(i, j, n)] = best;
        }
    }

    /* Copy results back into the original 2‑D vector */
    for (size_t i = 0; i < (size_t)n; ++i)
        std::copy(buf.begin() + i * n, buf.begin() + (i + 1) * n, table[i].begin());
}
