#include <vector>
#include <cstring>      // for std::memcpy
#include <cstddef>      // for std::size_t
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return.  The signature is kept identical
   to the original harness.  The body is rewritten to use a
   flattened, cache‑friendly layout and lightweight OpenMP
   parallelization. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* ------------------------------------------------------------------
       Step 1: Flatten the 2‑D matrix into a 1‑D array for faster access.
       ------------------------------------------------------------------ */
    const std::size_t N2 = static_cast<std::size_t>(n) * n;
    std::vector<double> Af(N2);                 // contiguous copy of A

    /* copy A into Af row‑major: Af[i*n + j] == A[i][j] */
    for (int i = 0; i < n; ++i)
        std::memcpy(&Af[i * n], A[i].data(), n * sizeof(double));

    /* ------------------------------------------------------------------
       Step 2: LU decomposition (Doolittle) with partial pivoting omitted
       because the original code assumes a non‑singular matrix.
       ------------------------------------------------------------------ */
    for (int i = 0; i < n; ++i) {
        /* (a) Upper part (U) */
        for (int j = i; j < n; ++j) {
            double w = Af[i * n + j];
            /* inner dot product */
            #pragma omp simd reduction(-:w)
            for (int k = 0; k < i; ++k)
                w -= Af[i * n + k] * Af[k * n + j];
            Af[i * n + j] = w;
        }

        /* (b) Lower part (L) */
        for (int j = i + 1; j < n; ++j) {
            double w = Af[j * n + i];
            #pragma omp simd reduction(-:w)
            for (int k = 0; k < i; ++k)
                w -= Af[j * n + k] * Af[k * n + i];
            Af[j * n + i] = w / Af[i * n + i];
        }
    }

    /* ------------------------------------------------------------------
       Step 3: Forward substitution (L * y = b)
       ------------------------------------------------------------------ */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        #pragma omp simd reduction(-:w)
        for (int j = 0; j < i; ++j)
            w -= Af[i * n + j] * y[j];
        y[i] = w;          // L[i][i] == 1
    }

    /* ------------------------------------------------------------------
       Step 4: Backward substitution (U * x = y)
       ------------------------------------------------------------------ */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        #pragma omp simd reduction(-:w)
        for (int j = i + 1; j < n; ++j)
            w -= Af[i * n + j] * x[j];
        x[i] = w / Af[i * n + i];
    }

    /* ------------------------------------------------------------------
       Step 5: Copy the result back into the original 2‑D vector A
       ------------------------------------------------------------------ */
    for (int i = 0; i < n; ++i)
        std::memcpy(A[i].data(), &Af[i * n], n * sizeof(double));
}
