/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
		std::vector<std::vector<double>>& E,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& F,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D,
		std::vector<std::vector<double>>& G)
{
    /* Parameters for blocking */
    const std::size_t BLOCK_I = 64;   // block size for outer i loops
    const std::size_t BLOCK_J = 64;   // block size for outer j loops
    const std::size_t BLOCK_K = 64;   // block size for inner k loops

    /* ---------- 1st GEMM : E = A * B  (ni x nk) * (nk x nj) ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += BLOCK_I)
    {
        for (int jj = 0; jj < nj; jj += BLOCK_J)
        {
            for (int i = ii; i < std::min(ii + BLOCK_I, ni); ++i)
            {
                double* const e_row = &E[i][jj];
                const double* const a_row = &A[i][0];
                for (int k = 0; k < nk; ++k)
                {
                    const double a_val = a_row[k];
                    const double* const b_row = &B[k][jj];
                    for (int j = 0; j < std::min(BLOCK_J, nj - jj); ++j)
                        e_row[j] += a_val * b_row[j];
                }
            }
        }
    }

    /* ---------- 2nd GEMM : F = C * D  (nj x nm) * (nm x nl) ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < nj; ii += BLOCK_I)
    {
        for (int jj = 0; jj < nl; jj += BLOCK_J)
        {
            for (int i = ii; i < std::min(ii + BLOCK_I, nj); ++i)
            {
                double* const f_row = &F[i][jj];
                const double* const c_row = &C[i][0];
                for (int k = 0; k < nm; ++k)
                {
                    const double c_val = c_row[k];
                    const double* const d_row = &D[k][jj];
                    for (int j = 0; j < std::min(BLOCK_J, nl - jj); ++j)
                        f_row[j] += c_val * d_row[j];
                }
            }
        }
    }

    /* ---------- 3rd GEMM : G = E * F  (ni x nj) * (nj x nl) ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += BLOCK_I)
    {
        for (int jj = 0; jj < nl; jj += BLOCK_J)
        {
            for (int i = ii; i < std::min(ii + BLOCK_I, ni); ++i)
            {
                double* const g_row = &G[i][jj];
                const double* const e_row = &E[i][0];
                for (int k = 0; k < nj; ++k)
                {
                    const double e_val = e_row[k];
                    const double* const f_row = &F[k][jj];
                    for (int j = 0; j < std::min(BLOCK_J, nl - jj); ++j)
                        g_row[j] += e_val * f_row[j];
                }
            }
        }
    }
