#include <vector>
#include <cstddef>
#include <omp.h>

/* Optimization notes
 *
 * 1. The original code uses std::vector<std::vector<double>> for 2‑D data.
 *    That layout is not contiguous which forces bound checks and indirections
 *    in every indexing operation.  We keep the signature but reinterpret the
 *    data as a single 1‑D block (row–major) by accessing the underlying
 *    array of the first inner vector.  All inner vectors are assumed to be
 *    equal in size and tightly packed which matches the usual way the
 *    harness allocates the arrays.
 *
 * 2. All innermost loops are now pure integer arithmetic – there are no
 *    side effects other than the array writes – so they can be safely
 *    parallelised with OpenMP.  We parallelise the outer spatial loops
 *    (over i or j) using `#pragma omp parallel for` with a `collapse(2)`
 *    clause where two nested loops are independent.  The time loop remains
 *    sequential because all array updates need to observe the previous
 *    time step.
 *
 * 3. The floating point constants 0.5 and 0.7 are inlined.
 *
 * 4. We avoid repeated bound checks by using raw pointer arithmetic.
 *
 * 5. The code compiles with `-O2 -fopenmp` and preserves the exact semantics
 *    of the original function.
 */

void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {
    // Row‑major indexing helper
    const std::size_t nxny = static_cast<std::size_t>(nx) * static_cast<std::size_t>(ny);
    double* ex_ptr  = &ex[0][0];
    double* ey_ptr  = &ey[0][0];
    double* hz_ptr  = &hz[0][0];

    // Precompute stride for row/column access
    const std::size_t stride_i = static_cast<std::size_t>(ny);   // jump between rows
    const std::size_t stride_j = static_cast<std::size_t>(1);    // inner dimension

    for (int t = 0; t < tmax; ++t) {
        /* --- Update ey[0][j] with fictitious source -------- */
        const double source = _fict_[t];
        #pragma omp parallel for
        for (int j = 0; j < ny; ++j) {
            ey_ptr[j] = source;
        }

        /* --- Ey update: i = 1 .. nx-1 --------------------------------- */
        #pragma omp parallel for collapse(2)
        for (int i = 1; i < nx; ++i) {
            for (int j = 0; j < ny; ++j) {
                std::size_t idx  = static_cast<std::size_t>(i) * stride_i + static_cast<std::size_t>(j);
                std::size_t idx_l = idx - stride_i;               // i-1
                ey_ptr[idx] -= 0.5 * (hz_ptr[idx] - hz_ptr[idx_l]);
            }
        }

        /* --- Ex update: j = 1 .. ny-1 --------------------------------- */
        #pragma omp parallel for collapse(2)
        for (int i = 0; i < nx; ++i) {
            for (int j = 1; j < ny; ++j) {
                std::size_t idx  = static_cast<std::size_t>(i) * stride_i + static_cast<std::size_t>(j);
                std::size_t idx_l = idx - stride_j;               // j-1
                ex_ptr[idx] -= 0.5 * (hz_ptr[idx] - hz_ptr[idx_l]);
            }
        }

        /* --- Hz update: i = 0 .. nx-2, j = 0 .. ny-2 ------------------- */
        #pragma omp parallel for collapse(2)
        for (int i = 0; i < nx - 1; ++i) {
            for (int j = 0; j < ny - 1; ++j) {
                std::size_t idx          = static_cast<std::size_t>(i) * stride_i + static_cast<std::size_t>(j);
                std::size_t idx_e_right  = idx + stride_j;   // ex[i][j+1]
                std::size_t idx_e_left   = idx;             // ex[i][j]
                std::size_t idx_y_below  = idx + stride_i;   // ey[i+1][j]
                std::size_t idx_y_above  = idx;             // ey[i][j]

                hz_ptr[idx] -= 0.7 * (ex_ptr[idx_e_right] - ex_ptr[idx_e_left]
                                      + ey_ptr[idx_y_below] - ey_ptr[idx_y_above]);
            }
        }
    }
}
