#include <cmath>
#include <vector>
#include <cstring>   // for memset
#include <immintrin.h> // for potential SIMD hints

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Optimized version of the original code.  The function signature is
   kept unchanged to preserve the harness interface. */

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* --------------  Compile‑time / run‑time constants -------------- */
    const float eA  = std::exp(-alpha);
    const float e2A = eA * eA;
    const float k = 1.0f - eA * (1.0f - eA) /
                     (1.0f + 2.0f * alpha * eA - e2A);

    /*  8 a–coefficients  */
    const float a1 = k, a2 = k * eA * (alpha - 1.0),
                 a3 = k * eA * (alpha + 1.0),
                 a4 = -k * e2A,
                 a5 = k, a6 = k * eA * (alpha - 1.0),
                 a7 = k * eA * (alpha + 1.0),
                 a8 = -k * e2A;

    /*  2 b–coefficients  */
    const float b1 = std::pow(2.0, -alpha),
                b2 = -e2A;

    /*  2 c–coefficients  */
    const float c1 = 1.0f, c2 = 1.0f;

    /* --------------  Use contiguous memory for speed -------------- */
    const int total = w * h;
    float *in  = new float[total];
    float *out = new float[total];
    float *col1= new float[total];
    float *col2= new float[total];

    /* Copy the 2‑D vectors into 1‑D temporaries (row major) */
#pragma omp parallel for
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in [i*h + j] = imgIn [i][j];

    /* ----------------------------------------------------------------
       Pass 1 – horizontal filtering (forward)
       ---------------------------------------------------------------- */
#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        int offset = i * h;
        for (int j = 0; j < h; ++j) {
            const float val = in[offset + j];
            const float y   = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            col1[offset + j] = y;
            xm1 = val;          ym2 = ym1;  ym1 = y;
        }
    }

    /* Pass 2 – horizontal filtering (backward) */
#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        int offset = i * h;
        for (int j = h-1; j >= 0; --j) {
            const float xp = in[offset + j];
            const float y  = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            col2[offset + j] = y;
            xp2 = xp1; xp1 = xp; yp2 = yp1; yp1 = y;
        }
    }

    /* Pass 3 – vertical blending of the two horizontal passes */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[i*h + j] = c1 * (col1[i*h + j] + col2[i*h + j]);

    /* Pass 4 – vertical filtering (forward) */
#pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float val = out[i*h + j];
            const float y   = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            col1[i*h + j] = y;
            tm1 = val; ym2 = ym1; ym1 = y;
        }
    }

    /* Pass 5 – vertical filtering (backward) */
#pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float tp = out[i*h + j];
            const float y  = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            col2[i*h + j] = y;
            tp2 = tp1; tp1 = tp; yp2 = yp1; yp1 = y;
        }
    }

    /* Pass 6 – final vertical blending */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[i*h + j] = c2 * (col1[i*h + j] + col2[i*h + j]);

    /* Copy result back into the 2‑D output vector */
#pragma omp parallel for
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[i*h + j];

    /* Also mirror the final result into the y1/y2 buffers (as in original) */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j) {
            y1[i][j] = col1[i*h + j];
            y2[i][j] = col2[i*h + j];
        }

    /* Clean‑up */
    delete[] in;
    delete[] out;
    delete[] col1;
    delete[] col2;
}
